import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = sanitizeUserInput(userInput);

        String output = "<html><body><h1>User Input: " + sanitizedInput + "</h1></body></html>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeUserInput(String input) {
        // Perform proper input validation and sanitization here
        // For example, you can use OWASP Java Encoder library to encode user input

        // Sample implementation using OWASP Java Encoder for HTML encoding:
        return org.owasp.encoder.Encode.forHtml(input);
    }
}

